mapper.select:
select mss.story_id as storyId, mss.story_name as storyName, agg.owner as owner, agg.show_status as planStatus, ifnull(agg.case_total_count, 0) as caseTotalCount, ifnull(agg.case_executed_count, 0) as caseExecutedCount, ifnull(agg.passed_count, 0) as passedCount, (select count(*) from ( select distinct cer.plan_id, cer.case_id from spotter_efficiency.case_execution_record cer inner join ( select tp.id as plan_id, tpfc.functional_case_id as case_id from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' inner join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci ) plan_case on cer.plan_id COLLATE utf8mb4_general_ci = plan_case.plan_id COLLATE utf8mb4_general_ci and cer.case_id COLLATE utf8mb4_general_ci = plan_case.case_id COLLATE utf8mb4_general_ci inner join ( select plan_id, case_id, min(create_time) as first_time from spotter_efficiency.case_execution_record group by plan_id, case_id ) first_t on first_t.plan_id COLLATE utf8mb4_general_ci = cer.plan_id COLLATE utf8mb4_general_ci and first_t.case_id COLLATE utf8mb4_general_ci = cer.case_id COLLATE utf8mb4_general_ci and first_t.first_time = cer.create_time where cer.exec_result in ('SUCCESS','PASS') ) fp) as firstPassCount, (select count(*) from ( select distinct cer.plan_id, cer.case_id from spotter_efficiency.case_execution_record cer inner join ( select tp.id as plan_id, tpfc.functional_case_id as case_id from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' inner join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci ) plan_case on cer.plan_id COLLATE utf8mb4_general_ci = plan_case.plan_id COLLATE utf8mb4_general_ci and cer.case_id COLLATE utf8mb4_general_ci = plan_case.case_id COLLATE utf8mb4_general_ci ) tot) as totalExecutedCountFromCer, agg.execution_period_start as executionPeriodStart, agg.execution_period_end as executionPeriodEnd, null as avgWriteDeviationRate, null as avgExecDeviationRate, mss.defect_count as defectCount, mss.reopen_rate as reopenRate, mss.code_coverage as codeCoverage, mss.frontend_defect_count as frontendDefectCount, mss.backend_defect_count as backendDefectCount, mss.frontend_loc_changed as frontendLocChanged, mss.backend_loc_changed as backendLocChanged, mss.deploy_total_count as deployTotalCount, mss.deploy_failure_count as deployFailureCount, mss.change_failure_rate as changeFailureRate from spotter_efficiency.meego_story_stats mss inner join ( select grp.feishu_story_id, max(grp.create_user) as owner, max(grp.status) as grp_status, count(distinct tpfc.functional_case_id) as case_total_count, count(distinct case when (tpfc.functional_case_id is not null) and (tpfc.last_exec_result is null or tpfc.last_exec_result = '' or tpfc.last_exec_result = 'PENDING') then tpfc.functional_case_id end) as pending_count, count(distinct case when tpfc.last_exec_result is not null and tpfc.last_exec_result != '' and tpfc.last_exec_result != 'PENDING' then tpfc.functional_case_id end) as case_executed_count, count(distinct case when tpfc.last_exec_result = 'SUCCESS' then tpfc.functional_case_id end) as passed_count, min(tp.create_time) as execution_period_start, coalesce(max(tpfc.last_exec_time), max(tp.actual_end_time), max(tp.planned_end_time), max(tp.update_time)) as execution_period_end, case when max(grp.status) = 'ARCHIVED' then 'ARCHIVED' when count(distinct tpfc.functional_case_id) = 0 then 'PREPARED' when count(distinct case when (tpfc.functional_case_id is not null) and (tpfc.last_exec_result is null or tpfc.last_exec_result = '' or tpfc.last_exec_result = 'PENDING') then tpfc.functional_case_id end) = 0 then 'COMPLETED' else 'UNDERWAY' end as show_status from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' left join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id is not null and grp.feishu_story_id != '' group by grp.feishu_story_id ) agg on agg.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci where 1=1
and mss.story_id COLLATE utf8mb4_general_ci in ( select distinct grp2.feishu_story_id COLLATE utf8mb4_general_ci from spotter_aegis.test_plan grp2 where grp2.type = 'GROUP' and grp2.feishu_story_id is not null and grp2.feishu_story_id != '' and grp2.project_id in
#{pid,jdbcType=VARCHAR}
)
and agg.show_status = #{status,jdbcType=VARCHAR}
and mss.story_id COLLATE utf8mb4_general_ci in
#{id,jdbcType=VARCHAR}
and (agg.execution_period_end is null or agg.execution_period_end >= #{executionPeriodStart,jdbcType=BIGINT})
and agg.execution_period_start <= #{executionPeriodEnd,jdbcType=BIGINT}
order by
agg.case_executed_count (ifnull(agg.case_executed_count, 0) * 1.0 / nullif(ifnull(agg.case_total_count, 0), 0)) (ifnull(agg.passed_count, 0) * 1.0 / nullif(ifnull(agg.case_total_count, 0), 0)) (firstPassCount * 1.0 / nullif(totalExecutedCountFromCer, 0)) mss.defect_count mss.reopen_rate mss.code_coverage mss.updated_at desc
limit #{pageSize,jdbcType=INTEGER} offset #{offset,jdbcType=BIGINT}

select count(*) from spotter_efficiency.meego_story_stats mss inner join ( select grp.feishu_story_id, min(tp.create_time) as execution_period_start, coalesce(max(tpfc.last_exec_time), max(tp.actual_end_time), max(tp.planned_end_time), max(tp.update_time)) as execution_period_end, case when max(grp.status) = 'ARCHIVED' then 'ARCHIVED' when count(distinct tpfc.functional_case_id) = 0 then 'PREPARED' when count(distinct case when (tpfc.functional_case_id is not null) and (tpfc.last_exec_result is null or tpfc.last_exec_result = '' or tpfc.last_exec_result = 'PENDING') then tpfc.functional_case_id end) = 0 then 'COMPLETED' else 'UNDERWAY' end as show_status from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' left join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id is not null and grp.feishu_story_id != ''
and grp.project_id in
#{pid,jdbcType=VARCHAR}
group by grp.feishu_story_id ) linked on linked.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci where 1=1
and linked.show_status = #{status,jdbcType=VARCHAR}
and mss.story_id COLLATE utf8mb4_general_ci in
#{id,jdbcType=VARCHAR}
and (linked.execution_period_end is null or linked.execution_period_end >= #{executionPeriodStart,jdbcType=BIGINT})
and linked.execution_period_start <= #{executionPeriodEnd,jdbcType=BIGINT}

select sum(ifnull(agg.case_total_count, 0)) as caseTotalCount, sum(ifnull(agg.case_executed_count, 0)) as caseExecutedCount, sum(ifnull(agg.passed_count, 0)) as passedCount, sum((select count(*) from ( select distinct cer.plan_id, cer.case_id from spotter_efficiency.case_execution_record cer inner join ( select tp.id as plan_id, tpfc.functional_case_id as case_id from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' inner join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci ) plan_case on cer.plan_id COLLATE utf8mb4_general_ci = plan_case.plan_id COLLATE utf8mb4_general_ci and cer.case_id COLLATE utf8mb4_general_ci = plan_case.case_id COLLATE utf8mb4_general_ci inner join ( select plan_id, case_id, min(create_time) as first_time from spotter_efficiency.case_execution_record group by plan_id, case_id ) first_t on first_t.plan_id COLLATE utf8mb4_general_ci = cer.plan_id COLLATE utf8mb4_general_ci and first_t.case_id COLLATE utf8mb4_general_ci = cer.case_id COLLATE utf8mb4_general_ci and first_t.first_time = cer.create_time where cer.exec_result in ('SUCCESS','PASS') ) fp)) as firstPassCount, sum((select count(*) from ( select distinct cer.plan_id, cer.case_id from spotter_efficiency.case_execution_record cer inner join ( select tp.id as plan_id, tpfc.functional_case_id as case_id from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' inner join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci ) plan_case on cer.plan_id COLLATE utf8mb4_general_ci = plan_case.plan_id COLLATE utf8mb4_general_ci and cer.case_id COLLATE utf8mb4_general_ci = plan_case.case_id COLLATE utf8mb4_general_ci ) tot)) as totalExecutedCountFromCer, avg(case when (select count(*) from ( select distinct cer.plan_id, cer.case_id from spotter_efficiency.case_execution_record cer inner join ( select tp.id as plan_id, tpfc.functional_case_id as case_id from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' inner join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci ) plan_case on cer.plan_id COLLATE utf8mb4_general_ci = plan_case.plan_id COLLATE utf8mb4_general_ci and cer.case_id COLLATE utf8mb4_general_ci = plan_case.case_id COLLATE utf8mb4_general_ci ) tot) > 0 then 100.0 * (select count(*) from ( select distinct cer.plan_id, cer.case_id from spotter_efficiency.case_execution_record cer inner join ( select tp.id as plan_id, tpfc.functional_case_id as case_id from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' inner join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci ) plan_case on cer.plan_id COLLATE utf8mb4_general_ci = plan_case.plan_id COLLATE utf8mb4_general_ci and cer.case_id COLLATE utf8mb4_general_ci = plan_case.case_id COLLATE utf8mb4_general_ci inner join ( select plan_id, case_id, min(create_time) as first_time from spotter_efficiency.case_execution_record group by plan_id, case_id ) first_t on first_t.plan_id COLLATE utf8mb4_general_ci = cer.plan_id COLLATE utf8mb4_general_ci and first_t.case_id COLLATE utf8mb4_general_ci = cer.case_id COLLATE utf8mb4_general_ci and first_t.first_time = cer.create_time where cer.exec_result in ('SUCCESS','PASS') ) fp) / (select count(*) from ( select distinct cer.plan_id, cer.case_id from spotter_efficiency.case_execution_record cer inner join ( select tp.id as plan_id, tpfc.functional_case_id as case_id from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' inner join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci ) plan_case on cer.plan_id COLLATE utf8mb4_general_ci = plan_case.plan_id COLLATE utf8mb4_general_ci and cer.case_id COLLATE utf8mb4_general_ci = plan_case.case_id COLLATE utf8mb4_general_ci ) tot) else null end) as avgFirstPassRate, avg(case when (ifnull(mss.frontend_loc_changed, 0) + ifnull(mss.backend_loc_changed, 0)) > 0 then (ifnull(mss.frontend_defect_count, 0) + ifnull(mss.backend_defect_count, 0)) * 1000.0 / (ifnull(mss.frontend_loc_changed, 0) + ifnull(mss.backend_loc_changed, 0)) else null end) as avgDefectRatePer1k from spotter_efficiency.meego_story_stats mss inner join ( select grp.feishu_story_id, count(distinct tpfc.functional_case_id) as case_total_count, count(distinct case when tpfc.last_exec_result is not null and tpfc.last_exec_result != '' and tpfc.last_exec_result != 'PENDING' then tpfc.functional_case_id end) as case_executed_count, count(distinct case when tpfc.last_exec_result = 'SUCCESS' then tpfc.functional_case_id end) as passed_count, min(tp.create_time) as execution_period_start, coalesce(max(tpfc.last_exec_time), max(tp.actual_end_time), max(tp.planned_end_time), max(tp.update_time)) as execution_period_end, case when max(grp.status) = 'ARCHIVED' then 'ARCHIVED' when count(distinct tpfc.functional_case_id) = 0 then 'PREPARED' when count(distinct case when (tpfc.functional_case_id is not null) and (tpfc.last_exec_result is null or tpfc.last_exec_result = '' or tpfc.last_exec_result = 'PENDING') then tpfc.functional_case_id end) = 0 then 'COMPLETED' else 'UNDERWAY' end as show_status from spotter_aegis.test_plan grp inner join spotter_aegis.test_plan tp on tp.group_id = grp.id and tp.type = 'TEST_PLAN' left join spotter_aegis.test_plan_functional_case tpfc on tpfc.test_plan_id = tp.id where grp.type = 'GROUP' and grp.feishu_story_id is not null and grp.feishu_story_id != '' group by grp.feishu_story_id ) agg on agg.feishu_story_id COLLATE utf8mb4_general_ci = mss.story_id COLLATE utf8mb4_general_ci where 1=1
and mss.story_id COLLATE utf8mb4_general_ci in ( select distinct grp2.feishu_story_id COLLATE utf8mb4_general_ci from spotter_aegis.test_plan grp2 where grp2.type = 'GROUP' and grp2.feishu_story_id is not null and grp2.feishu_story_id != '' and grp2.project_id in
#{pid,jdbcType=VARCHAR}
)
and agg.show_status = #{status,jdbcType=VARCHAR}
and mss.story_id COLLATE utf8mb4_general_ci in
#{id,jdbcType=VARCHAR}
and (agg.execution_period_end is null or agg.execution_period_end >= #{executionPeriodStart,jdbcType=BIGINT})
and agg.execution_period_start <= #{executionPeriodEnd,jdbcType=BIGINT}
